// 1. Interface ilə object type
interface Item {
  name: string;
  price: number;
}
const item: Item = { name: "Shirt", price: 50 };
// item.price = "50"; // Xəta: string number tipinə uyğun deyil

// 2. Type ilə object type
type Product = {
  id: number;
  inStock: boolean;
};
const product: Product = { id: 1, inStock: true };

// 3. Object type ilə funksiya
function printItem(item: Item): string {
  return `${item.name}: $${item.price}`;
}

// 4. Nested object type
interface Order {
  orderId: number;
  items: Item[];
}
const order: Order = {
  orderId: 101,
  items: [{ name: "Jacket", price: 100 }, { name: "Hat", price: 25 }]
};

// 5. Opsiyonel xüsusiyyətlər
interface User {
  name: string;
  email?: string; // ? opsiyonel olduğunu göstərir
}
const user: User = { name: "Alice" }; // email olmadan da düzgündür

